solution: ```class Solution {
    public int minSwaps(int[] nums) {
        int n = nums.length;
        int ones = 0;
        for (int num : nums) ones += num;
        if (ones == 0 || ones == n) return 0;

        int[] doubled = new int[2 * n];
        for (int i = 0; i < n; i++) doubled[i] = doubled[i + n] = nums[i];

        int zeros = 0;
        for (int i = 0; i < ones; i++) if (doubled[i] == 0) zeros++;

        int minSwaps = zeros;
        for (int i = ones; i < 2 * n; i++) {
            if (doubled[i - ones] == 0) zeros--;
            if (doubled[i] == 0) zeros++;
            if (i >= n && i - ones < n) {
                minSwaps = Math.min(minSwaps, zeros);
            }
        }
        return minSwaps;
    }
}```
